/* ==========================================================
   名称：紫月魔法书
   样式作者：@Junezz
   版本：v1.0
   发布于：类脑 Discord 社区

   本样式仅供个人使用与参考，禁止任何形式的商用。
   可二改不可二传。请保留本注释和原作者署名。
   ========================================================== */

@import url("https://fontsapi.zeoseven.com/570/main/result.css");

body {
    font-family: "Fusion Pixel 12px Monospaced zh_hans";
    font-weight: normal;
    background: linear-gradient(135deg, #1a0a2e 0%, #0d051a 50%, #150a30 100%);
}

code, textarea, #send_textarea, input, select, button, .text_pole, .font-family-reset {
  font-family: inherit;
}

:root {
    --mainFontSize: calc(var(--fontScale)* 16px);
    --avatar-base-width: 48px;
    --avatar-base-height: 48px;
    --topbarIconSize: calc(var(--mainFontSize)* 1.3);
    --genericRadius: 12px;
    --warning: #ce3636;
    --crimson70a: #acacac63;
    --crimson-hover: color-mix(in srgb, var(--SmartThemeUnderlineColor), transparent 90%) !important;
    --standardIconSize: calc(var(--mainFontSize)* 1);
    --bottomFormIconSize: calc(var(--mainFontSize)* 1.5);
    --bottomFormBlockPadding: calc(var(--mainFontSize) / 1.5);
    --scrollBarWidth: 6px;
    --pagePadding: calc(var(--scrollBarWidth) + 9px);
    --genericLineHeight: calc(var(--mainFontSize)* 1.9);

    --utilityColor: rgba(180, 150, 200, 0.7);
    --navBackgroundColor: rgba(30, 15, 60, 0.9);
    --buttonFill: rgba(40, 25, 80, 0.8);
    --menuBackgroundColor: rgba(25, 12, 50, 0.95);
    --accentColor: rgba(180, 120, 220, 0.8);
    --accentColorOverlay: rgba(100, 60, 150, 0.3);
    --scrollBarColor: rgba(160, 100, 200, 0.8);
    --boxShadowSubtle: 0 0 15px rgba(140, 80, 180, 0.3), 0 4px 20px rgba(0, 0, 0, 0.5);
    --boxShadowSubtleAlt: 0 0 10px rgba(200, 150, 100, 0.2);
    --goldColor: rgba(230, 200, 160, 0.9);
    --purpleGlow: rgba(140, 80, 200, 0.5);
}

#chat {
    background: transparent;
    padding: 20px;
}

#sheld {
    max-width: 800px;
    margin: 0 auto;
    border: 1px solid rgba(140, 100, 180, 0.4);
    border-radius: 20px;
    box-shadow: 0 0 40px rgba(100, 50, 150, 0.2), inset 0 0 60px rgba(0, 0, 0, 0.5);
    overflow: hidden;
}

#chat > div:first-child {
    background: linear-gradient(180deg, rgba(60, 30, 100, 0.6) 0%, transparent 100%);
    padding: 30px 20px 20px;
    text-align: center;
    border-bottom: 1px solid rgba(140, 100, 180, 0.3);
}

#chat > div:first-child::before {
    content: '\2605';
    position: absolute;
    top: 10px;
    left: 20px;
    color: rgba(230, 200, 160, 0.6);
    font-size: 16px;
    animation: twinkle 3s ease-in-out infinite;
}

#chat > div:first-child::after {
    content: '\263D';
    position: absolute;
    top: 15px;
    right: 25px;
    color: rgba(230, 200, 160, 0.6);
    font-size: 20px;
}

@keyframes twinkle {
    0%, 100% { opacity: 0.3; }
    50% { opacity: 1; }
}

#top-bar {
    background: linear-gradient(180deg, rgba(40, 20, 70, 0.9) 0%, rgba(25, 12, 50, 0.8) 100%) !important;
    border: 1px solid rgba(140, 100, 180, 0.4) !important;
    border-radius: 12px 12px 0 0;
    box-shadow: 0 0 20px rgba(100, 50, 150, 0.2);
}

#send_form {
    background: linear-gradient(180deg, rgba(25, 12, 50, 0.9) 0%, rgba(40, 20, 70, 0.9) 100%) !important;
    border: 1px solid rgba(140, 100, 180, 0.4) !important;
    border-radius: 0 0 12px 12px;
    box-shadow: 0 0 20px rgba(100, 50, 150, 0.2);
}

.mes {
    padding: 15px 0;
    position: relative;
}

.mes::before {
    content: '';
    position: absolute;
    top: 0;
    left: 50%;
    transform: translateX(-50%);
    width: 80%;
    height: 1px;
    background: linear-gradient(90deg, transparent, rgba(140, 100, 180, 0.3), transparent);
}

.mes:first-child::before {
    display: none;
}

.mes_block {
    background: rgba(30, 15, 50, 0.6);
    border: 1px solid rgba(140, 100, 180, 0.3);
    border-radius: 16px;
    padding: 15px 20px !important;
    box-shadow: 0 4px 20px rgba(0, 0, 0, 0.3), inset 0 0 30px rgba(100, 50, 150, 0.05);
}

.mes[is_user="true"] .mes_block {
    background: rgba(40, 25, 70, 0.6);
    border-color: rgba(160, 120, 200, 0.4);
}

.ch_name {
    color: rgba(230, 200, 160, 0.9) !important;
    font-weight: bold;
    letter-spacing: 2px;
    margin-bottom: 10px;
    position: relative;
}

.ch_name::after {
    content: '';
    position: absolute;
    bottom: -5px;
    left: 0;
    width: 30px;
    height: 1px;
    background: linear-gradient(90deg, rgba(230, 200, 160, 0.8), transparent);
}

.mes_text {
    color: rgba(220, 200, 180, 0.95);
    line-height: 1.8;
    font-size: calc(var(--mainFontSize));
}

.mes_text p {
    margin-bottom: 12px;
}

.mes_text p:last-child {
    margin-bottom: 0;
}

.mes_text q {
    color: rgba(200, 170, 140, 0.9);
    background: rgba(100, 60, 150, 0.3);
    border-left: 3px solid rgba(230, 200, 160, 0.8);
    padding: 8px 15px;
    margin: 10px 0;
    display: block;
    border-radius: 0 8px 8px 0;
    box-shadow: inset -5px 0 15px rgba(140, 80, 180, 0.2);
}

.mes_text blockquote {
    background: rgba(60, 30, 100, 0.4);
    border-left: 3px solid rgba(180, 120, 220, 0.8);
    padding: 15px 20px;
    margin: 15px 0;
    border-radius: 0 10px 10px 0;
    position: relative;
}

.mes_text blockquote::before {
    content: '""';
    position: absolute;
    top: -10px;
    right: 15px;
    font-size: 40px;
    color: rgba(230, 200, 160, 0.2);
    font-family: serif;
}

.mes_text a {
    color: rgba(180, 140, 220, 0.9);
    text-decoration: none;
    border-bottom: 1px dashed rgba(180, 140, 220, 0.5);
    transition: all 0.3s ease;
}

.mes_text a:hover {
    color: rgba(230, 200, 160, 1);
    border-bottom-color: rgba(230, 200, 160, 0.8);
    text-shadow: 0 0 10px rgba(230, 200, 160, 0.5);
}

.mes_text code {
    background: rgba(80, 40, 120, 0.6);
    color: rgba(200, 160, 220, 0.9);
    padding: 3px 8px;
    border-radius: 6px;
    font-size: 0.9em;
    border: 1px solid rgba(140, 100, 180, 0.4);
}

.mes_text pre {
    background: rgba(30, 15, 50, 0.9);
    border: 1px solid rgba(140, 100, 180, 0.3);
    border-radius: 12px;
    padding: 15px;
    overflow-x: auto;
    position: relative;
    box-shadow: inset 0 0 30px rgba(0, 0, 0, 0.5);
}

.mes_text pre::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    height: 2px;
    background: linear-gradient(90deg, rgba(140, 80, 180, 0.6), rgba(230, 200, 160, 0.4), rgba(140, 80, 180, 0.6));
    border-radius: 12px 12px 0 0;
}

.mes_text hr {
    border: none;
    height: 1px;
    background: linear-gradient(90deg, transparent, rgba(140, 100, 180, 0.4), transparent);
    margin: 20px 0;
}

.mes_text ul, .mes_text ol {
    padding-left: 25px;
    margin: 10px 0;
}

.mes_text li {
    margin-bottom: 8px;
    position: relative;
}

.mes_text ul li::marker {
    color: rgba(180, 140, 200, 0.8);
}

.mes_text ol li::marker {
    color: rgba(230, 200, 160, 0.8);
}

.mesAvatarWrapper {
    padding-bottom: 10px !important;
}

.avatar {
    border: 2px solid rgba(140, 100, 180, 0.5) !important;
    border-radius: 10px !important;
    box-shadow: 0 0 15px rgba(100, 50, 150, 0.3);
}

::-webkit-scrollbar {
    width: 8px;
}

::-webkit-scrollbar-track {
    background: rgba(20, 10, 35, 0.5);
}

::-webkit-scrollbar-thumb {
    background: linear-gradient(180deg, rgba(160, 100, 200, 0.8), rgba(100, 60, 150, 0.6));
    border-radius: 4px;
    border: 2px solid rgba(20, 10, 35, 0.5);
}

::-webkit-scrollbar-thumb:hover {
    background: linear-gradient(180deg, rgba(180, 120, 220, 0.9), rgba(120, 80, 170, 0.7));
}

#send_textarea {
    background: rgba(20, 10, 35, 0.6) !important;
    border: 1px solid rgba(140, 100, 180, 0.3) !important;
    border-radius: 8px;
    color: rgba(220, 200, 180, 0.9);
    padding: 12px 15px;
}

#send_textarea::placeholder {
    color: rgba(150, 120, 180, 0.5);
}

.menu_button {
    background: rgba(50, 30, 90, 0.8) !important;
    border: 1px solid rgba(140, 100, 180, 0.4) !important;
    border-radius: 8px;
    color: rgba(220, 200, 180, 0.9) !important;
    box-shadow: 0 4px 15px rgba(0, 0, 0, 0.3);
    transition: all 0.3s ease;
}

.menu_button:hover {
    background: rgba(80, 50, 130, 0.9) !important;
    border-color: rgba(180, 140, 220, 0.6) !important;
    box-shadow: 0 0 20px rgba(140, 100, 180, 0.3);
}

input[type='checkbox'] {
    background: rgba(40, 25, 70, 0.8);
    border: 1px solid rgba(140, 100, 180, 0.5);
    border-radius: 4px;
}

input[type='checkbox']:checked {
    background: rgba(140, 100, 180, 0.6);
}

select, .text_pole, textarea {
    background: rgba(30, 15, 50, 0.8) !important;
    border: 1px solid rgba(140, 100, 180, 0.4) !important;
    border-radius: 8px;
    color: rgba(220, 200, 180, 0.9) !important;
}

.mes_edit_buttons {
    filter: drop-shadow(0 0 10px rgba(140, 100, 180, 0.3));
}

.mes_edit_buttons .menu_button {
    color: rgba(220, 200, 180, 0.9) !important;
}

.mes_reasoning_header {
    background: rgba(40, 25, 70, 0.6) !important;
    border: 1px solid rgba(140, 100, 180, 0.4) !important;
    border-radius: 10px;
    color: rgba(230, 200, 160, 0.9) !important;
    box-shadow: 0 0 15px rgba(100, 50, 150, 0.2);
}

.mes_reasoning_header:hover {
    background: rgba(60, 40, 100, 0.7) !important;
    border-color: rgba(180, 140, 220, 0.6) !important;
}

.mes_reasoning {
    border-left: 3px solid rgba(180, 120, 220, 0.6) !important;
    background: rgba(30, 15, 50, 0.4) !important;
    padding: 15px;
    margin: 10px 0;
    border-radius: 0 8px 8px 0;
}

.script-group-header {
    background: rgba(60, 30, 100, 0.5) !important;
    border-bottom: 1px solid rgba(140, 100, 180, 0.4);
}

.title-item-active {
    background: rgba(80, 50, 130, 0.6) !important;
    border-bottom: 2px solid rgba(230, 200, 160, 0.8);
}

.toggle-input:checked + .toggle-label {
    background: rgba(140, 100, 180, 0.7) !important;
    border-color: rgba(180, 140, 220, 0.6) !important;
}

#completion_prompt_manager_list li.completion_prompt_manager_prompt {
    background: rgba(30, 15, 50, 0.8) !important;
    border: 1px solid rgba(140, 100, 180, 0.3) !important;
    border-radius: 10px;
}

#completion_prompt_manager_list li.completion_prompt_manager_prompt:hover {
    border-color: rgba(180, 140, 220, 0.5) !important;
}

.quick-reply-menu {
    background: rgba(25, 12, 50, 0.95) !important;
    border: 1px solid rgba(140, 100, 180, 0.4) !important;
    border-radius: 12px;
    box-shadow: 0 0 30px rgba(100, 50, 150, 0.3);
}

.quick-reply-item {
    background: rgba(40, 25, 70, 0.7) !important;
    border-radius: 8px;
    color: rgba(220, 200, 180, 0.9) !important;
}

.quick-reply-item:hover {
    background: rgba(60, 40, 100, 0.8) !important;
}

.character_select.is_fav .ch_name {
    color: rgba(230, 200, 160, 1) !important;
}

.character_select.is_fav .avatar {
    outline: 2px solid rgba(230, 200, 160, 0.8) !important;
    box-shadow: 0 0 15px rgba(230, 200, 160, 0.4);
}

.popup-content {
    background: rgba(25, 12, 50, 0.98) !important;
    border: 1px solid rgba(140, 100, 180, 0.4) !important;
    border-radius: 15px;
    box-shadow: 0 0 40px rgba(100, 50, 150, 0.3);
}

.drawer-content {
    background: rgba(20, 10, 35, 0.98) !important;
    border: 1px solid rgba(140, 100, 180, 0.3);
}

#character_popup, #world_popup {
    background: rgba(25, 12, 50, 0.98) !important;
    border: 1px solid rgba(140, 100, 180, 0.4) !important;
    border-radius: 15px;
}

#settings-panel input, #settings-panel select, #settings-panel textarea {
    background: rgba(30, 15, 50, 0.8) !important;
    border: 1px solid rgba(140, 100, 180, 0.4) !important;
    color: rgba(220, 200, 180, 0.9) !important;
}

#HotSwapWrapper > div {
    background: rgba(20, 10, 35, 0.6);
    border-radius: 12px;
    padding: 10px;
}

.avatar-container.selected {
    border: 2px solid rgba(230, 200, 160, 0.8) !important;
    box-shadow: 0 0 15px rgba(230, 200, 160, 0.4);
}

.add_avatar:hover {
    filter: drop-shadow(0 0 10px rgba(180, 140, 220, 0.6));
}

@media (max-width: 600px) {
    #sheld {
        margin: 10px;
        border-radius: 15px;
    }

    .mes_block {
        padding: 12px 15px !important;
        border-radius: 12px;
    }

    #chat {
        padding: 10px;
    }
}

@supports (-webkit-touch-callout: none) {
    #chat {
        padding-right: var(--pagePadding);
    }
}
